// ── Source detection ──────────────────────────────────────────
// Inspect payload structure to identify the alert source

const payload = $input.first().json.body || $input.first().json;

let source = 'generic';

if (payload.issueId && payload.entitySnapshot) {
  source = 'wiz';
} else if (payload.cid && payload.behaviors) {
  source = 'crowdstrike';
} else if (payload.attributes && payload.rule && payload.priority?.startsWith('P')) {
  source = 'datadog';
}

// ── Severity mapping helpers ───────────────────────────────────

function mapCrowdStrikeSeverity(score) {
  if (score >= 75) return 'critical';
  if (score >= 50) return 'high';
  if (score >= 25) return 'medium';
  return 'low';
}

function mapDatadogSeverity(priority) {
  const map = { P1: 'critical', P2: 'high', P3: 'medium', P4: 'low', P5: 'info' };
  return map[priority] || 'medium';
}

function normaliseWizSeverity(sev) {
  return (sev || '').toLowerCase();
}

// ── Normalisation ──────────────────────────────────────────────

let normalised = {};

if (source === 'wiz') {
  const snap = payload.entitySnapshot || {};
  normalised = {
    alert_id:      payload.issueId,
    source:        'wiz',
    severity:      normaliseWizSeverity(payload.severity),
    title:         payload.control?.name || 'Unknown Wiz Finding',
    description:   payload.control?.description || '',
    resource_id:   snap.id || '',
    resource_type: (snap.type || 'other').toLowerCase().replace('_', ''),
    cloud_account: snap.subscriptionId || '',
    region:        snap.region || '',
    owner_tag:     snap.tags?.owner || '',
    env_tag:       snap.tags?.env || '',
    timestamp:     payload.createdAt || new Date().toISOString(),
    raw_payload:   JSON.stringify(payload)
  };

} else if (source === 'crowdstrike') {
  normalised = {
    alert_id:      payload.id,
    source:        'crowdstrike',
    severity:      mapCrowdStrikeSeverity(payload.severity),
    title:         payload.name || 'Unknown CrowdStrike Detection',
    description:   payload.description || '',
    resource_id:   payload.device_id || payload.hostname || '',
    resource_type: (payload.platform || 'other').toLowerCase(),
    cloud_account: payload.account_id || '',
    region:        payload.region || '',
    owner_tag:     payload.tags?.owner || '',
    env_tag:       payload.tags?.env || '',
    timestamp:     payload.timestamp || new Date().toISOString(),
    raw_payload:   JSON.stringify(payload)
  };

} else if (source === 'datadog') {
  const regionTag = (payload.tags || []).find(t => t.startsWith('region:'));
  const ownerTag  = (payload.tags || []).find(t => t.startsWith('owner:'));
  const envTag    = (payload.tags || []).find(t => t.startsWith('env:'));

  normalised = {
    alert_id:      payload.id,
    source:        'datadog',
    severity:      mapDatadogSeverity(payload.priority),
    title:         payload.name || 'Unknown Datadog Signal',
    description:   payload.message || '',
    resource_id:   payload.attributes?.userIdentity?.arn || payload.host || '',
    resource_type: (payload.source_type_name || 'other').toLowerCase(),
    cloud_account: payload.org_name || '',
    region:        regionTag ? regionTag.replace('region:', '') : '',
    owner_tag:     ownerTag  ? ownerTag.replace('owner:', '')   : '',
    env_tag:       envTag    ? envTag.replace('env:', '')       : '',
    timestamp:     payload.timestamp || new Date().toISOString(),
    raw_payload:   JSON.stringify(payload)
  };

} else {
  // Generic fallback — pass through what we can
  normalised = {
    alert_id:      payload.id || `generic-${Date.now()}`,
    source:        'generic',
    severity:      (payload.severity || 'medium').toLowerCase(),
    title:         payload.title || payload.name || 'Unknown Alert',
    description:   payload.description || payload.message || '',
    resource_id:   payload.resource_id || payload.host || '',
    resource_type: payload.resource_type || 'other',
    cloud_account: payload.account_id || payload.cloud_account || '',
    region:        payload.region || '',
    owner_tag:     payload.tags?.owner || '',
    env_tag:       payload.tags?.env || '',
    timestamp:     payload.timestamp || new Date().toISOString(),
    raw_payload:   JSON.stringify(payload)
  };
}

// Add ingestion timestamp
normalised.ingested_at = new Date().toISOString();

// Validate required fields
const required = ['alert_id', 'source', 'severity', 'title'];
const missing  = required.filter(f => !normalised[f]);

if (missing.length > 0) {
  throw new Error(`Validation failed — missing required fields: ${missing.join(', ')}`);
}

return [{ json: normalised }];
